using System;
using System.Linq;
using System.Reflection;

var asm = Assembly.LoadFrom("/home/runner/.nuget/packages/microsoft.agents.ai/1.4.0/lib/net10.0/Microsoft.Agents.AI.dll");

void InspectType(string name)
{
    var type = asm.GetExportedTypes().FirstOrDefault(t => t.Name == name);
    if (type == null) { Console.WriteLine($"Type {name} not found"); return; }
    Console.WriteLine($"\n=== {type.FullName} ===");
    Console.WriteLine($"Base: {type.BaseType?.FullName}");
    Console.WriteLine($"Interfaces: {string.Join(", ", type.GetInterfaces().Select(i => i.Name))}");

    foreach (var c in type.GetConstructors(BindingFlags.Public | BindingFlags.Instance))
    {
        var ps = string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  ctor({ps})");
    }
    foreach (var p in type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
    {
        Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");
    }
    foreach (var m in type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
        .Where(m => !m.IsSpecialName))
    {
        var ps = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  method {m.ReturnType.Name} {m.Name}({ps})");
    }
}

InspectType("ChatClientAgent");
InspectType("ChatClientAgentOptions");
InspectType("ChatClientAgentRunOptions");
InspectType("AIAgentBuilder");
InspectType("AIAgentExtensions");
