    if (runMethod.ReturnType.IsGenericType)
    {
        var innerType = runMethod.ReturnType.GetGenericArguments()[0];
        Console.WriteLine($"Inner type: {innerType.FullName}");
        InspectType(asm, innerType.Name);
    }
}

// Check AgentResponseUpdate (streaming)
