using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capability to the research agent.
/// Uses a simple HTTP-based search to find relevant information on a topic.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Search the web for information on a given query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to find information about")] string query,
        [Description("Maximum number of results to return (1-5)")] int maxResults = 3)
    {
        maxResults = Math.Clamp(maxResults, 1, 5);

        try
        {
            // Use Wikipedia's search API as a free, no-key-required search source
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit={maxResults}&format=json&utf8=1";

            var response = await _httpClient.GetAsync(url);
            response.EnsureSuccessStatusCode();

            using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());
            var searchResults = doc.RootElement
                .GetProperty("query")
                .GetProperty("search");

            var results = new List<SearchResult>();
            foreach (var item in searchResults.EnumerateArray())
            {
                var title = item.GetProperty("title").GetString() ?? "";
                var snippet = item.GetProperty("snippet").GetString() ?? "";
                // Strip HTML tags from snippet
                snippet = System.Text.RegularExpressions.Regex.Replace(snippet, "<.*?>", "");
                var pageId = item.GetProperty("pageid").GetInt64();

                results.Add(new SearchResult
                {
                    Title = title,
                    Snippet = snippet,
                    Url = $"https://en.wikipedia.org/wiki/{Uri.EscapeDataString(title.Replace(' ', '_'))}"
                });
            }

            if (results.Count == 0)
                return "No results found for the query.";

            return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
        }
        catch (HttpRequestException ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch the content of a web page given its URL. Returns the text content of the page (truncated to first 2000 characters).")]
    public async Task<string> FetchPageContentAsync(
        [Description("The URL of the page to fetch")] string url)
    {
        try
        {
            var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.Add("User-Agent", "ResearchAgent/1.0");

            var response = await _httpClient.GetAsync(url);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync();

            // Basic HTML-to-text: strip tags and decode entities
            var text = System.Text.RegularExpressions.Regex.Replace(html, "<script[^>]*>.*?</script>", "", System.Text.RegularExpressions.RegexOptions.Singleline);
            text = System.Text.RegularExpressions.Regex.Replace(text, "<style[^>]*>.*?</style>", "", System.Text.RegularExpressions.RegexOptions.Singleline);
            text = System.Text.RegularExpressions.Regex.Replace(text, "<.*?>", " ");
            text = System.Net.WebUtility.HtmlDecode(text);
            text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ").Trim();

            // Truncate to keep within token limits
            if (text.Length > 2000)
                text = text[..2000] + "... [truncated]";

            return text;
        }
        catch (HttpRequestException ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private sealed class SearchResult
    {
        public string Title { get; set; } = "";
        public string Snippet { get; set; } = "";
        public string Url { get; set; } = "";
    }
}

using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capability for the research agent to organize findings.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<ResearchNote> _notes = [];

    [Description("Save a research note with a title and content. Use this to record key findings during research.")]
    public string AddNote(
        [Description("A short title for the note")] string title,
        [Description("The content/body of the note with the research finding")] string content,
        [Description("The source URL where this information was found")] string sourceUrl = "")
    {
        var note = new ResearchNote
        {
            Id = _notes.Count + 1,
            Title = title,
            Content = content,
            SourceUrl = sourceUrl,
            CreatedAt = DateTime.UtcNow
        };
        _notes.Add(note);
        return $"Note #{note.Id} saved: \"{title}\"";
    }

    [Description("Retrieve all saved research notes. Use this to review findings before writing a summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        return JsonSerializer.Serialize(_notes, new JsonSerializerOptions { WriteIndented = true });
    }

    [Description("Get the total number of research notes saved so far.")]
    public string GetNoteCount()
    {
        return $"Total notes saved: {_notes.Count}";
    }

    public IReadOnlyList<ResearchNote> Notes => _notes;

    public sealed class ResearchNote
    {
        public int Id { get; set; }
        public string Title { get; set; } = "";
        public string Content { get; set; } = "";
        public string SourceUrl { get; set; } = "";
        public DateTime CreatedAt { get; set; }
    }
}

