using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Set up the chat client via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create tool instances ---
var httpClient = new HttpClient();
var webSearchTool = new WebSearchTool(httpClient);
var noteTakingTool = new NoteTakingTool();

// --- Register tools as AIFunctions ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearchTool.SearchWebAsync, "search_web",
        "Search the web for information on a given query"),
    AIFunctionFactory.Create(webSearchTool.FetchPageContentAsync, "fetch_page",
        "Fetch the text content of a web page given its URL"),
    AIFunctionFactory.Create(noteTakingTool.AddNote, "add_note",
        "Save a research note with a title, content, and optional source URL"),
    AIFunctionFactory.Create(noteTakingTool.GetAllNotes, "get_all_notes",
        "Retrieve all saved research notes"),
    AIFunctionFactory.Create(noteTakingTool.GetNoteCount, "get_note_count",
        "Get the total number of research notes saved"),
};

// --- Create the research agent ---
const string agentInstructions = """
    You are a Research Agent. Your job is to research a topic thoroughly and produce
    a well-organized summary of your findings.

    Follow this workflow:
    1. Use the search_web tool to find relevant information about the topic.
    2. For promising results, use fetch_page to get more detailed content.
    3. Use add_note to save key findings as you go (include source URLs).
    4. After gathering enough information (at least 3 notes), use get_all_notes
       to review your findings.
    5. Produce a final summary that synthesizes your research notes into a coherent,
       well-structured response with source citations.

    Be thorough but concise. Focus on factual, verifiable information.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: agentInstructions,
    name: "ResearchAgent",
    description: "An AI agent that researches topics using web search and note-taking",
    tools: tools,
    loggerFactory: null,
    services: null);

// --- Get the research topic ---
string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "artificial intelligence";
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");
Console.WriteLine(new string('─', 60));

// --- Run the agent ---
var session = await agent.CreateSessionAsync("research-session");

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    options: null))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();
Console.WriteLine(new string('─', 60));
Console.WriteLine($"\n📝 Research complete. {noteTakingTool.Notes.Count} notes were collected.");

